     1|import { createGateway, generateText, streamText } from 'ai';
     2|import { acquireAIQueueSlot, classifyRequestLane, type IVXAIQueueLane } from './services/ivx-ai-queue';
     3|import { estimatePromptTokens, recordProviderTelemetry } from './services/ivx-provider-telemetry';
     4|import { attemptProviderFallback, classifyProviderFailure, isFailureRetryable } from './services/ivx-ai-provider-fallback';
     5|
     6|export type IVXAIModule = 'owner-room' | 'p0-ai-assistant' | 'p1-plan-creator' | 'public-chat' | string;
     7|export type IVXAIMessageRole = 'user' | 'assistant';
     8|
     9|export type IVXAITextMessage = {
    10|  role: IVXAIMessageRole;
    11|  content: string;
    12|};
    13|
    14|export type IVXAIImageAttachment = {
    15|  url: string;
    16|  mimeType?: string | null;
    17|};
    18|
    19|/**
    20| * A non-image binary attachment (PDF for OCR, video for understanding) passed to
    21| * a multimodal model as a `file` content part. `data` may be a URL, a base64
    22| * string, or raw bytes.
    23| */
    24|export type IVXAIFileAttachment = {
    25|  data: string | Uint8Array | ArrayBuffer;
    26|  mediaType: string;
    27|  filename?: string | null;
    28|};
    29|
    30|export type IVXAIProviderMetadata = {
    31|  provider: 'chatgpt';
    32|  source: 'remote_api';
    33|  model: string;
    34|  endpoint: string | null;
    35|  runtime: 'vercel_ai_gateway';
    36|  ivxAI: {
    37|    architecture: 'ivx-ai';
    38|    phase: 'agent_runtime_v2';
    39|    layer: 'ivx_ai_runtime_wrapper';
    40|    module: string;
    41|    providerDependency: 'chatgpt_current_baseline';
    42|    requestId: string | null;
    43|    generatedAt: string;
    44|  };
    45|};
    46|
    47|export type IVXAITextResult = {
    48|  text: string;
    49|  usage: unknown;
    50|  providerMetadata: IVXAIProviderMetadata;
    51|};
    52|
    53|type IVXAIGatewayFailureContext = {
    54|  module: string;
    55|  requestId: string | null;
    56|  model: string;
    57|  endpoint: string | null;
    58|  status?: number | null;
    59|  responseBody?: unknown;
    60|};
    61|
    62|export type IVXAIConfigurationSnapshot = {
    63|  configured: boolean;
    64|  hasGatewayUrl: boolean;
    65|  hasGatewayApiKey: boolean;
    66|  model: string;
    67|  endpoint: string | null;
    68|  runtime: 'vercel_ai_gateway';
    69|  layer: 'ivx_ai_runtime_wrapper';
    70|  phase: 'agent_runtime_v2';
    71|};
    72|
    73|const GATEWAY_BASE_PATH = '/v3/ai';
    74|// Full multimodal model billed against the paid Vercel AI Gateway balance.
    75|// gpt-4o-mini is a free-tier model that Vercel rate-limits and is the weakest
    76|// vision model; gpt-4o gives real image + document analysis with no free-tier
    77|// caps. Override with IVX_AI_MODEL / PUBLIC_CHAT_MODEL / OPENAI_MODEL if needed.
    78|const DEFAULT_IVX_AI_MODEL = readTrimmed(process.env.IVX_AI_MODEL) || 'openai/gpt-4o';
    79|
    80|// Adaptive timeout floor / ceiling. Short prompts resolve fast (floor), large
    81|// reports get more headroom (ceiling). Tuned so a 12k-token report has ~90s
    82|// to complete instead of dying at the legacy 8s wall.
    83|const IVX_AI_TIMEOUT_FLOOR_MS = (() => {
    84|  const raw = Number.parseInt(readTrimmed(process.env.IVX_AI_GATEWAY_TIMEOUT_MS) || '15000', 10);
    85|  return Number.isFinite(raw) && raw > 0 ? raw : 15_000;
    86|})();
    87|const IVX_AI_TIMEOUT_CEIL_MS = (() => {
    88|  const raw = Number.parseInt(readTrimmed(process.env.IVX_AI_GATEWAY_TIMEOUT_CEIL_MS) || '120000', 10);
    89|  return Number.isFinite(raw) && raw > 0 ? raw : 120_000;
    90|})();
    91|
    92|/**
    93| * Compute an adaptive hard timeout based on the size of the work.
    94| *
    95| * Budget heuristics:
    96| *  - Base latency: floor (covers handshake + first-token latency)
    97| *  - Output budget: ~50ms per maxOutputToken (gpt-4o-mini sustains ~20 tok/s)
    98| *  - Prompt budget: ~2ms per prompt char (covers large context ingestion)
    99| * Clamped to [floor, ceiling].
   100| */
   101|export function computeAdaptiveTimeoutMs(input: {
   102|  promptChars: number;
   103|  maxOutputTokens: number | null | undefined;
   104|}): number {
   105|  const outputBudget = (input.maxOutputTokens ?? 1500) * 50;
   106|  const promptBudget = input.promptChars * 2;
   107|  const budget = IVX_AI_TIMEOUT_FLOOR_MS + outputBudget + promptBudget;
   108|  return Math.min(IVX_AI_TIMEOUT_CEIL_MS, Math.max(IVX_AI_TIMEOUT_FLOOR_MS, budget));
   109|}
   110|
   111|function runWithHardTimeout<T>(label: string, promise: Promise<T>, timeoutMs: number): Promise<T> {
   112|  return new Promise<T>((resolve, reject) => {
   113|    const timer = setTimeout(() => {
   114|      const err = new Error(`${label} timed out after ${timeoutMs}ms`);
   115|      err.name = 'IVXAIGatewayTimeoutError';
   116|      reject(err);
   117|    }, timeoutMs);
   118|    promise.then(
   119|      (value) => {
   120|        clearTimeout(timer);
   121|        resolve(value);
   122|      },
   123|      (error) => {
   124|        clearTimeout(timer);
   125|        reject(error);
   126|      },
   127|    );
   128|  });
   129|}
   130|
   131|function readTrimmed(value: unknown): string {
   132|  return typeof value === 'string' ? value.trim() : '';
   133|}
   134|
   135|function nowIso(): string {
   136|  return new Date().toISOString();
   137|}
   138|
   139|// Backend MUST talk directly to the canonical Vercel AI Gateway so the paid
   140|// AI_GATEWAY_API_KEY bearer reaches Vercel intact. Any client-facing proxy
   141|// (EXPO_PUBLIC_IVX_AI_GATEWAY_URL, e.g. ai.ivxholding.com) is intended for
   142|// the frontend only and may strip the Authorization header, which causes the
   143|// gateway to fall back to anonymous free-tier rate limits and return the
   144|// "Free tier requests on this model are rate-limited" 429 even when the
   145|// account has paid balance. The server-only override IVX_AI_GATEWAY_URL is
   146|// honored for advanced routing; otherwise we go direct to Vercel.
   147|function getIVXAIGatewayRootUrl(): string {
   148|  const configured = readTrimmed(process.env.IVX_AI_GATEWAY_URL);
   149|  // Rork independence guard (2026-07-07): never honor a gateway URL that
   150|  // points at a Rork-hosted domain, even if a stale env var is still set on
   151|  // the host. This makes the runtime self-healing: production cannot route
   152|  // through toolkit.rork.com regardless of env var state.
   153|  if (configured && !isRorkDomain(configured)) {
   154|    return configured;
   155|  }
   156|  return 'https://ai-gateway.vercel.sh';
   157|}
   158|
   159|function getIVXAIGatewayApiKey(): string {
   160|  return readTrimmed(process.env.AI_GATEWAY_API_KEY);
   161|}
   162|
   163|function buildGatewayBaseUrl(rootUrl: string): string | null {
   164|  const gatewayRootUrl = readTrimmed(rootUrl).replace(/\/+$/, '');
   165|  if (!gatewayRootUrl) {
   166|    return null;
   167|  }
   168|
   169|  if (gatewayRootUrl.endsWith('/v3/ai') || gatewayRootUrl.endsWith(GATEWAY_BASE_PATH)) {
   170|    return gatewayRootUrl;
   171|  }
   172|
   173|  return new URL(GATEWAY_BASE_PATH, `${gatewayRootUrl}/`).toString().replace(/\/+$/, '');
   174|}
   175|
   176|function getGatewayBaseUrl(): string | null {
   177|  return buildGatewayBaseUrl(getIVXAIGatewayRootUrl());
   178|}
   179|
   180|function isRorkDomain(url: string): boolean {
   181|  const lower = url.toLowerCase();
   182|  return lower.includes('toolkit.rork.com')
   183|    || lower.includes('api.rork.com')
   184|    || lower.endsWith('.rork.com')
   185|    || lower.includes('rork-direct.workers.dev');
   186|}
   187|
   188|function getGatewayBaseUrlCandidates(): string[] {
   189|  const configured = getGatewayBaseUrl();
   190|  const canonical = buildGatewayBaseUrl('https://ai-gateway.vercel.sh');
   191|  // Always include the canonical Vercel gateway as a fallback candidate so a
   192|  // misconfigured IVX_AI_GATEWAY_URL cannot strand the backend on a proxy that
   193|  // strips auth headers (which causes free-tier 429s on a paid account).
   194|  //
   195|  // Rork toolkit cutover (2026-07-07): the Rork toolkit URL is no longer a
   196|  // candidate. The IVX AI runtime now relies exclusively on IVX-owned
   197|  // providers: the Vercel AI Gateway (AI_GATEWAY_API_KEY) as primary, and
   198|  // OpenAI direct / Anthropic direct as fallbacks (see
   199|  // ivx-ai-provider-fallback.ts). If none of these keys are configured the
   200|  // runtime throws a clear configuration error instead of silently falling
   201|  // back to a Rork-hosted endpoint.
   202|  //
   203|  // Rork independence guard (2026-07-07): any candidate that resolves to a
   204|  // Rork domain is filtered out, so a stale IVX_AI_GATEWAY_URL env var on the
   205|  // host cannot silently re-route production through toolkit.rork.com.
   206|  const candidates = [configured, canonical].filter((c): c is string => c !== null && !isRorkDomain(c));
   207|
   208|  return [...new Set(candidates)];
   209|}
   210|
   211|function ensureIVXAIGatewayEnvironment(): void {
   212|  const apiKey = getIVXAIGatewayApiKey();
   213|  if (!apiKey) {
   214|    // Rork toolkit cutover (2026-07-07): the Rork toolkit key is no longer
   215|    // accepted as a gateway bearer. The runtime now requires an IVX-owned
   216|    // provider key: AI_GATEWAY_API_KEY (Vercel AI Gateway, primary) or
   217|    // OPENAI_API_KEY / ANTHROPIC_API_KEY (direct fallbacks, handled by
   218|    // attemptProviderFallback in ivx-ai-provider-fallback.ts).
   219|    throw new Error(
   220|      'IVX AI runtime is not configured. Set AI_GATEWAY_API_KEY (Vercel AI Gateway) ' +
   221|        'or OPENAI_API_KEY / ANTHROPIC_API_KEY (direct fallbacks) on the backend host.',
   222|    );
   223|  }
   224|
   225|  if (!readTrimmed(process.env.AI_GATEWAY_API_KEY)) {
   226|    process.env.AI_GATEWAY_API_KEY = apiKey;
   227|  }
   228|}
   229|
   230|// Rork toolkit cutover (2026-07-07): the Rork toolkit native URL, key
   231|// resolver, isRorkToolkitBaseUrl, and callRorkToolkitNative function have been
   232|// removed. The IVX AI runtime no longer routes to toolkit.rork.com under any
   233|// condition. All AI traffic now flows through IVX-owned providers: the Vercel
   234|// AI Gateway (AI_GATEWAY_API_KEY) as primary, and OpenAI direct / Anthropic
   235|// direct as fallbacks (see ivx-ai-provider-fallback.ts).
   236|
   237|function readRecord(value: unknown): Record<string, unknown> {
   238|  return typeof value === 'object' && value !== null ? value as Record<string, unknown> : {};
   239|}
   240|
   241|function extractGatewayFailureContext(error: unknown): { status: number | null; responseBody: unknown } {
   242|  const record = readRecord(error);
   243|  const response = readRecord(record.response);
   244|  const cause = readRecord(record.cause);
   245|  const status = typeof record.statusCode === 'number'
   246|    ? record.statusCode
   247|    : typeof record.status === 'number'
   248|      ? record.status
   249|      : typeof record.responseStatus === 'number'
   250|        ? record.responseStatus
   251|        : typeof response.status === 'number'
   252|          ? response.status
   253|          : typeof cause.status === 'number'
   254|            ? cause.status
   255|            : null;
   256|  const responseBody = record.responseBody
   257|    ?? response.body
   258|    ?? response.data
   259|    ?? record.data
   260|    ?? record.body
   261|    ?? cause.responseBody
   262|    ?? cause.body
   263|    ?? null;
   264|  return { status, responseBody };
   265|}
   266|
   267|function normalizeGatewayFailure(error: unknown, context: IVXAIGatewayFailureContext): Error {
   268|  const message = error instanceof Error ? error.message : 'Gateway request failed';
   269|  const body = typeof context.responseBody === 'string'
   270|    ? context.responseBody.slice(0, 600)
   271|    : context.responseBody && typeof context.responseBody === 'object'
   272|      ? JSON.stringify(context.responseBody).slice(0, 600)
   273|      : null;
   274|  const detail = [
   275|    `IVX AI gateway request failed for ${context.module}.`,
   276|    `endpoint=${context.endpoint ?? 'unresolved'}`,
   277|    `model=${context.model}`,
   278|    context.status ? `status=${context.status}` : null,
   279|    `providerError=${message}`,
   280|    body ? `responseBody=${body}` : null,
   281|  ].filter(Boolean).join(' ');
   282|  const normalized = new Error(detail);
   283|  normalized.name = 'IVXAIGatewayRequestError';
   284|  return normalized;
   285|}
   286|
   287|function normalizeMessages(messages: IVXAITextMessage[] | undefined): IVXAITextMessage[] {
   288|  return (messages ?? [])
   289|    .map((message) => ({
   290|      role: message.role === 'assistant' ? 'assistant' as const : 'user' as const,
   291|      content: readTrimmed(message.content),
   292|    }))
   293|    .filter((message) => message.content.length > 0);
   294|}
   295|
   296|export function resolveIVXAIModel(explicitModel?: string | null, envCandidates: string[] = []): string {
   297|  const explicit = readTrimmed(explicitModel);
   298|  if (explicit) {
   299|    return explicit;
   300|  }
   301|
   302|  for (const envName of envCandidates) {
   303|    const candidate = readTrimmed(process.env[envName]);
   304|    if (candidate) {
   305|      return candidate;
   306|    }
   307|  }
   308|
   309|  return DEFAULT_IVX_AI_MODEL;
   310|}
   311|
   312|export function getIVXAIEndpoint(model: string = DEFAULT_IVX_AI_MODEL): string | null {
   313|  const baseUrl = getGatewayBaseUrl();
   314|  if (!baseUrl) {
   315|    return null;
   316|  }
   317|
   318|  return `${baseUrl}/${model}`;
   319|}
   320|
   321|export function isIVXAIConfigured(): boolean {
   322|  return getIVXAIGatewayRootUrl().length > 0 && getIVXAIGatewayApiKey().length > 0;
   323|}
   324|
   325|export function getIVXAIConfigurationSnapshot(model: string = DEFAULT_IVX_AI_MODEL): IVXAIConfigurationSnapshot {
   326|  const hasGatewayUrl = getIVXAIGatewayRootUrl().length > 0;
   327|  const hasGatewayApiKey = getIVXAIGatewayApiKey().length > 0;
   328|  return {
   329|    configured: hasGatewayUrl && hasGatewayApiKey,
   330|    hasGatewayUrl,
   331|    hasGatewayApiKey,
   332|    model,
   333|    endpoint: getIVXAIEndpoint(model),
   334|    runtime: 'vercel_ai_gateway',
   335|    layer: 'ivx_ai_runtime_wrapper',
   336|    phase: 'agent_runtime_v2',
   337|  };
   338|}
   339|
   340|export async function requestIVXAIText(input: {
   341|  module: IVXAIModule;
   342|  requestId?: string | null;
   343|  model?: string | null;
   344|  system?: string | null;
   345|  prompt?: string | null;
   346|  messages?: IVXAITextMessage[];
   347|  images?: IVXAIImageAttachment[];
   348|  files?: IVXAIFileAttachment[];
   349|  maxOutputTokens?: number;
   350|}): Promise<IVXAITextResult> {
   351|  const model = resolveIVXAIModel(input.model);
   352|  const endpoint = getIVXAIEndpoint(model);
   353|  const messages = normalizeMessages(input.messages);
   354|  const prompt = readTrimmed(input.prompt);
   355|  const system = readTrimmed(input.system);
   356|  const images = (input.images ?? [])
   357|    .map((img) => ({ url: readTrimmed(img.url), mimeType: readTrimmed(img.mimeType ?? '') || null }))
   358|    .filter((img) => img.url.length > 0);
   359|  const files = (input.files ?? []).filter(
   360|    (file) => readTrimmed(file.mediaType).length > 0 && file.data != null,
   361|  );
   362|
   363|  if (!prompt && messages.length === 0) {
   364|    throw new Error('IVX AI request requires a prompt or messages.');
   365|  }
   366|
   367|  const baseUrlCandidates = getGatewayBaseUrlCandidates();
   368|  if (baseUrlCandidates.length === 0) {
   369|    throw new Error('IVX AI runtime is not configured.');
   370|  }
   371|
   372|  console.log('[IVXAI] Routing request through IVX AI Phase 1 wrapper:', {
   373|    module: input.module,
   374|    requestId: input.requestId ?? null,
   375|    model,
   376|    endpoint,
   377|    baseUrlCandidates,
   378|    hasSystem: system.length > 0,
   379|    promptLength: prompt.length,
   380|    messageCount: messages.length,
   381|    authKeySource: 'AI_GATEWAY_API_KEY',
   382|    requestShape: messages.length > 0 ? 'messages' : 'prompt',
   383|    maxOutputTokens: input.maxOutputTokens ?? null,
   384|    phase: 'agent_runtime_v2',
   385|    layer: 'ivx_ai_runtime_wrapper',
   386|  });
   387|
   388|  // Adaptive timeout + queue gating: long prompts/reports get more time and a
   389|  // dedicated lane so they cannot block normal chat under contention.
   390|  const promptChars = prompt.length + system.length + messages.reduce((sum, m) => sum + m.content.length, 0);
   391|  const adaptiveTimeoutMs = computeAdaptiveTimeoutMs({ promptChars, maxOutputTokens: input.maxOutputTokens });
   392|  const queueLane: IVXAIQueueLane = classifyRequestLane({ promptChars, maxOutputTokens: input.maxOutputTokens });
   393|  const queueSlot = await acquireAIQueueSlot(queueLane);
   394|  const callStartedAt = Date.now();
   395|
   396|  let result: Awaited<ReturnType<typeof generateText>> | null = null;
   397|  let lastError: unknown = null;
   398|  let lastFailure: { status: number | null; responseBody: unknown } = { status: null, responseBody: null };
   399|  let successfulBaseUrl = baseUrlCandidates[0];
   400|  let retryCount = 0;
   401|
   402|  for (const baseURL of baseUrlCandidates) {
   403|    ensureIVXAIGatewayEnvironment();
   404|    try {
   405|      const gatewayProvider = createGateway({
   406|        apiKey: getIVXAIGatewayApiKey(),
   407|        baseURL,
   408|      });
   409|      const callTimeoutMs = adaptiveTimeoutMs;
   410|      if (images.length > 0 || files.length > 0) {
   411|        // Multimodal request: build a single user message with text + image/file
   412|        // parts so multimodal models (gpt-4o family for images/PDF OCR, video-
   413|        // capable models for video) can actually see the attachments.
   414|        const baseMessages = messages.length > 0
   415|          ? messages.slice(0, -1)
   416|          : [];
   417|        const lastTextMessage = messages.length > 0 ? messages[messages.length - 1] : null;
   418|        const userText = readTrimmed(
   419|          (lastTextMessage && lastTextMessage.role === 'user' ? lastTextMessage.content : '') || prompt
   420|        ) || 'Describe the attached file(s).';
   421|        const multimodalUser = {
   422|          role: 'user' as const,
   423|          content: [
   424|            { type: 'text' as const, text: userText },
   425|            ...images.map((img) => ({ type: 'image' as const, image: img.url })),
   426|            ...files.map((file) => ({ type: 'file' as const, data: file.data, mediaType: file.mediaType })),
   427|          ],
   428|        };
   429|        const finalMessages = lastTextMessage && lastTextMessage.role === 'user'
   430|          ? [...baseMessages, multimodalUser]
   431|          : [...messages, multimodalUser];
   432|        result = await runWithHardTimeout('IVX AI gateway (multimodal)', generateText({
   433|          model: gatewayProvider(model),
   434|          system: system.length > 0 ? system : undefined,
   435|          maxOutputTokens: input.maxOutputTokens,
   436|          // eslint-disable-next-line @typescript-eslint/no-explicit-any
   437|          messages: finalMessages as any,
   438|        }), callTimeoutMs);
   439|      } else {
   440|        result = messages.length > 0
   441|          ? await runWithHardTimeout('IVX AI gateway (messages)', generateText({
   442|              model: gatewayProvider(model),
   443|              system: system.length > 0 ? system : undefined,
   444|              maxOutputTokens: input.maxOutputTokens,
   445|              messages,
   446|            }), callTimeoutMs)
   447|          : await runWithHardTimeout('IVX AI gateway (prompt)', generateText({
   448|              model: gatewayProvider(model),
   449|              system: system.length > 0 ? system : undefined,
   450|              maxOutputTokens: input.maxOutputTokens,
   451|              prompt,
   452|            }), callTimeoutMs);
   453|      }
   454|      successfulBaseUrl = baseURL;
   455|      break;
   456|    } catch (error) {
   457|      retryCount += 1;
   458|      const failure = extractGatewayFailureContext(error);
   459|      lastError = error;
   460|      lastFailure = failure;
   461|      console.error('[IVXAI] Gateway request failed:', {
   462|        module: input.module,
   463|        requestId: input.requestId ?? null,
   464|        model,
   465|            endpoint: `${baseURL}/${model}`,
   466|        status: failure.status,
   467|        error: error instanceof Error ? error.message : 'Gateway request failed',
   468|        responseBodyType: typeof failure.responseBody,
   469|        responseBodyPreview: typeof failure.responseBody === 'string'
   470|          ? failure.responseBody.slice(0, 400)
   471|          : failure.responseBody && typeof failure.responseBody === 'object'
   472|            ? JSON.stringify(failure.responseBody).slice(0, 400)
   473|            : null,
   474|        errorName: error instanceof Error ? error.name : null,
   475|      });
   476|    }
   477|  }
   478|
   479|  if (!result) {
   480|    queueSlot.release();
   481|    const failureMessage = lastError instanceof Error ? lastError.message : 'Gateway request failed';
   482|    const isTimeout = lastError instanceof Error && lastError.name === 'IVXAIGatewayTimeoutError';
   483|
   484|    // Multi-provider fallback chain. Only invoked when:
   485|    //   - all primary gateway base URLs failed
   486|    //   - failure is in a retryable class (timeout / rate_limit / quota / 5xx / network)
   487|    //   - at least one fallback provider has its env key configured
   488|    // Fallbacks NEVER log API keys or prompt content.
   489|    const failureClass = classifyProviderFailure(lastError);
   490|    if (isFailureRetryable(failureClass)) {
   491|      const fallbackResult = await attemptProviderFallback({
   492|        module: String(input.module),
   493|        requestId: input.requestId ?? null,
   494|        system,
   495|        prompt,
   496|        messages,
   497|        maxOutputTokens: input.maxOutputTokens ?? null,
   498|        timeoutMs: adaptiveTimeoutMs,
   499|      });
   500|      if (fallbackResult) {
   501|        const fallbackMetadata: IVXAIProviderMetadata = {
   502|          provider: 'chatgpt',
   503|          source: 'remote_api',
   504|          model: fallbackResult.model,
   505|          endpoint: null,
   506|          runtime: 'vercel_ai_gateway',
   507|          ivxAI: {
   508|            architecture: 'ivx-ai',
   509|            phase: 'agent_runtime_v2',
   510|            layer: 'ivx_ai_runtime_wrapper',
   511|            module: input.module,
   512|            providerDependency: 'chatgpt_current_baseline',
   513|            requestId: input.requestId ?? null,
   514|            generatedAt: nowIso(),
   515|          },
   516|        };
   517|        recordProviderTelemetry({
   518|          traceId: input.requestId ?? null,
   519|          module: String(input.module),
   520|          model: fallbackResult.model,
   521|          endpoint: null,
   522|          promptChars,
   523|          promptTokensEstimated: estimatePromptTokens(promptChars),
   524|          completionTokens: null,
