    37|  // "100 minus 20", "50 divided by 2", "square root of 144"
    38|  if (detectMathQuestion(compact)) return 'math';
    39|
    40|  // Greetings
    41|  const greetings = ['hello', 'hi ', 'hey', 'hola', 'good morning', 'good afternoon', 'good evening', 'buenos dias', 'buenas tardes'];
    42|  if (greetings.some((g) => compact === g.trim() || compact.startsWith(g) || compact === g.trim())) return 'greeting';
    43|
    44|  // Thanks
    45|  const thanks = ['thank you', 'thanks', 'gracias', 'much appreciated', 'ty '];
    46|  if (thanks.some((t) => compact === t.trim() || compact.startsWith(t))) return 'thanks';
    47|
    48|  // Capabilities / "what can you do"
