    58|/**
    59| * Detect and evaluate a math question.
    60| * Handles: plus, minus, multiplied by, times, divided by, x, *, /, +, -, sqrt.
    61| */
    62|function detectMathQuestion(compact: string): boolean {
    63|  // Word-form arithmetic
    64|  const wordMath = /\b(\d+(?:\.\d+)?)\s+(plus|minus|multiplied by|times|divided by|added to|subtracted from)\s+(\d+(?:\.\d+)?)/;
    65|  if (wordMath.test(compact)) return true;
    66|  // Symbol-form arithmetic
    67|  const symMath = /\b(\d+(?:\.\d+)?)\s*[+\-*/x]\s*(\d+(?:\.\d+)?)/;
    68|  if (symMath.test(compact) && /\b(\d+(?:\.\d+)?)\s*[+\-*/x]\s*(\d+(?:\.\d+)?)/.test(compact)) return true;
    69|  // "what is N op N"
    70|  if (/\bwhat is\s+/ .test(compact) && wordMath.test(compact)) return true;
    71|  // square root
    72|  if (/\b(square root|sqrt)\s+of\s+\d+/.test(compact)) return true;
    73|  return false;
