    81|  // square root
    82|  const sqrtMatch = text.match(/(?:square root|sqrt)\s+of\s+(\d+(?:\.\d+)?)/);
    83|  if (sqrtMatch) {
    84|    const n = parseFloat(sqrtMatch[1]);
    85|    return Math.sqrt(n);
    86|  }
    87|  // word-form
    88|  const wordMatch = text.match(/(\d+(?:\.\d+)?)\s+(plus|minus|multiplied by|times|divided by|added to|subtracted from)\s+(\d+(?:\.\d+)?)/);
    89|  if (wordMatch) {
    90|    const a = parseFloat(wordMatch[1]);
    91|    const op = wordMatch[2];
    92|    const b = parseFloat(wordMatch[3]);
    93|    switch (op) {
    94|      case 'plus': case 'added to': return a + b;
    95|      case 'minus': case 'subtracted from': return op === 'subtracted from' ? b - a : a - b;
    96|      case 'multiplied by': case 'times': return a * b;
    97|      case 'divided by': return b === 0 ? null : a / b;
    98|    }
    99|  }
