    18|
    19|export type IVXProviderName = 'vercel_ai_gateway' | 'openai_direct' | 'anthropic_direct';
    20|export type IVXProviderFailureClass =
    21|  | 'auth'
    22|  | 'quota'
    23|  | 'rate_limit'
    24|  | 'timeout'
    25|  | 'network'
    26|  | 'bad_request'
    27|  | 'server_error'
    28|  | 'unknown';
    29|
    30|export type IVXProviderStatus = {
    31|  name: IVXProviderName;
    32|  role: 'primary' | 'fallback';
    33|  configured: boolean;
