    33|  | 'read_files'
    34|  | 'write_files'
    35|  | 'run_tests'
    36|  | 'commit'
    37|  | 'push_github'
    38|  | 'trigger_render_deploy'
    39|  | 'query_supabase'
    40|  | 'migrate_database'
    41|  | 'verify_live_endpoint'
    42|  | 'verify_owner_session';
    43|
    44|export type RequiredCredential =
