   115|
   116|// ─── Task → required capabilities decomposition ─────────────────────
   117|
   118|export type TaskIntent =
   119|  | 'read_only_inspection'
   120|  | 'patch_code'
   121|  | 'commit'
   122|  | 'push_github'
   123|  | 'trigger_render_deploy'
   124|  | 'query_supabase'
   125|  | 'migrate_database'
   126|  | 'verify_live_endpoint'
   127|  | 'verify_owner_session'
   128|  | 'full_deploy_cycle'
   129|  | 'conversational';
   130|
   131|/**
   132| * Classify the prompt into a task intent. Deterministic, pure — used to derive
   133| * the required capability set. Conservative: any ambiguous developer verb
   134| * routes to the most demanding intent so the gate verifies the full chain.
   135| */
   136|export function classifyTaskIntent(prompt: string): TaskIntent {
   137|  const text = prompt.toLowerCase();
   138|  if (/deploy\s+now|full\s+deploy|push\s+and\s+deploy/.test(text)) return 'full_deploy_cycle';
   139|  if (/push\s+(this\s+)?commit|push\s+to\s+(github|main)/.test(text)) return 'push_github';
   140|  if (/trigger\s+render|render\s+deploy/.test(text)) return 'trigger_render_deploy';
   141|  if (/run\s+supabase\s+migration|migrate\s+database|apply\s+migration/.test(text)) return 'migrate_database';
   142|  if (/query\s+supabase|read\s+from\s+supabase|supabase\s+read/.test(text)) return 'query_supabase';
   143|  if (/verify\s+(live|production)|health\s+check|is\s+this\s+verified/.test(text)) return 'verify_live_endpoint';
   144|  if (/fix\s+owner\s+login|owner\s+session|owner\s+auth/.test(text)) return 'verify_owner_session';
   145|  if (/commit\s+(this|the|now)|git\s+commit/.test(text)) return 'commit';
   146|  if (/patch|modify|edit|fix\s+(the\s+)?(?:bug|code|file)|update\s+(the\s+)?code|write\s+(?:a\s+)?file/.test(text)) return 'patch_code';
   147|  if (/inspect|audit|review|read|explain|show\s+me|status/.test(text)) return 'read_only_inspection';
   148|  return 'conversational';
   149|}
   150|
   151|/**
   152| * Map a task intent to the capabilities it requires. The order matters — the
   153| * gate checks them in this order and the FIRST failure produces the blocker.
   154| */
   155|export function requiredCapabilitiesFor(intent: TaskIntent): CapabilityId[] {
   156|  switch (intent) {
   157|    case 'full_deploy_cycle':
   158|      return ['verify_owner_session', 'write_files', 'run_tests', 'commit', 'push_github', 'trigger_render_deploy', 'verify_live_endpoint'];
   159|    case 'push_github':
   160|      return ['verify_owner_session', 'commit', 'push_github'];
   161|    case 'trigger_render_deploy':
   162|      return ['verify_owner_session', 'trigger_render_deploy', 'verify_live_endpoint'];
   163|    case 'migrate_database':
   164|      return ['verify_owner_session', 'migrate_database', 'query_supabase'];
   165|    case 'query_supabase':
   166|      return ['verify_owner_session', 'query_supabase'];
   167|    case 'verify_live_endpoint':
   168|      return ['verify_live_endpoint'];
   169|    case 'verify_owner_session':
   170|      return ['verify_owner_session'];
   171|    case 'commit':
   172|      return ['verify_owner_session', 'write_files', 'commit'];
   173|    case 'patch_code':
   174|      return ['verify_owner_session', 'write_files', 'run_tests'];
   175|    case 'read_only_inspection':
   176|      return ['read_files'];
   177|    case 'conversational':
   178|      return [];
   179|  }
   180|}
   181|
   182|// ─── Masking helpers ─────────────────────────────────────────────────
   183|
   184|/** Mask a credential to its first 8 chars + ellipsis. Never the full value. */
   185|export function maskCredential(value: string): string | null {
   186|  if (!value) return null;
   187|  const prefix = value.slice(0, 8);
   188|  return prefix.length < value.length ? `${prefix}…` : prefix;
   189|}
   190|
   191|// ─── Live credential probe (injectable for tests) ────────────────────
   192|
   193|export type CredentialProbeResult = {
   194|  ok: boolean;
   195|  httpStatus: number | null;
   196|  detail: string;
   197|};
   198|
   199|export type CredentialProbeMap = Partial<
   200|  Record<RequiredCredential, (value: string) => Promise<CredentialProbeResult>>
   201|>;
   202|
   203|/**
   204| * Default live probes. Each calls the real API and returns ok/httpStatus/detail.
   205| * Never throws — network errors return ok:false with the message in detail.
   206| */
   207|export const DEFAULT_CREDENTIAL_PROBES: CredentialProbeMap = {
   208|  IVX_GITHUB_TOKEN: async (token: string): Promise<CredentialProbeResult> => {
   209|    try {
   210|      const res = await fetch('https://api.github.com/user', {
   211|        headers: {
   212|          Authorization: `Bearer ${token}`,
   213|          Accept: 'application/vnd.github+json',
   214|          'X-GitHub-Api-Version': '2022-11-28',
   215|        },
   216|        signal: AbortSignal.timeout(10_000),
   217|      });
   218|      if (res.status === 200) return { ok: true, httpStatus: 200, detail: 'authenticated' };
   219|      return { ok: false, httpStatus: res.status, detail: res.status === 401 ? 'token invalid or expired' : `HTTP ${res.status}` };
   220|    } catch (err) {
   221|      return { ok: false, httpStatus: null, detail: `network error: ${err instanceof Error ? err.message : String(err)}` };
   222|    }
   223|  },
   224|  IVX_RENDER_API_KEY: async (token: string): Promise<CredentialProbeResult> => {
   225|    try {
   226|      const res = await fetch('https://api.render.com/v1/owners', {
   227|        headers: { Authorization: `Bearer ${token}`, Accept: 'application/json' },
   228|        signal: AbortSignal.timeout(10_000),
   229|      });
   230|      if (res.status === 200) return { ok: true, httpStatus: 200, detail: 'authenticated' };
   231|      return { ok: false, httpStatus: res.status, detail: res.status === 401 ? 'token invalid' : `HTTP ${res.status}` };
   232|    } catch (err) {
   233|      return { ok: false, httpStatus: null, detail: `network error: ${err instanceof Error ? err.message : String(err)}` };
   234|    }
   235|  },
   236|  IVX_RENDER_SERVICE_ID: async (_id: string): Promise<CredentialProbeResult> => {
   237|    if (_id.length < 8) return { ok: false, httpStatus: null, detail: 'service id too short (shape check)' };
   238|    return { ok: true, httpStatus: null, detail: 'shape check passed' };
   239|  },
   240|  IVX_SUPABASE_URL: async (url: string): Promise<CredentialProbeResult> => {
   241|    try {
   242|      const res = await fetch(`${url.replace(/\/$/, '')}/rest/v1/`, {
   243|        headers: { Accept: 'application/json' },
   244|        signal: AbortSignal.timeout(10_000),
   245|      });
   246|      if (res.status < 500) return { ok: true, httpStatus: res.status, detail: `reachable (HTTP ${res.status})` };
   247|      return { ok: false, httpStatus: res.status, detail: `HTTP ${res.status} — server error` };
   248|    } catch (err) {
   249|      return { ok: false, httpStatus: null, detail: `unreachable: ${err instanceof Error ? err.message : String(err)}` };
   250|    }
   251|  },
   252|  IVX_SUPABASE_SERVICE_ROLE_KEY: async (key: string): Promise<CredentialProbeResult> => {
   253|    const url = getVaultValue('IVX_SUPABASE_URL', 'SUPABASE_URL');
   254|    if (!url) return { ok: false, httpStatus: null, detail: 'cannot test — SUPABASE_URL also missing' };
   255|    try {
   256|      const res = await fetch(`${url.replace(/\/$/, '')}/rest/v1/`, {
   257|        headers: { apikey: key, Authorization: `Bearer ${key}` },
   258|        signal: AbortSignal.timeout(10_000),
   259|      });
   260|      if (res.status === 200) return { ok: true, httpStatus: 200, detail: 'service role authenticated' };
   261|      return { ok: false, httpStatus: res.status, detail: res.status === 401 ? 'key invalid' : `HTTP ${res.status}` };
   262|    } catch (err) {
   263|      return { ok: false, httpStatus: null, detail: `network error: ${err instanceof Error ? err.message : String(err)}` };
   264|    }
   265|  },
   266|  IVX_OWNER_TOKEN: async (token: string): Promise<CredentialProbeResult> => {
   267|    if (token.length < 16) return { ok: false, httpStatus: null, detail: 'too short to be a real owner token' };
   268|    return { ok: true, httpStatus: null, detail: 'shape check passed' };
   269|  },
   270|};
   271|
   272|// ─── Blocker memory (spin-loop prevention) ───────────────────────────
   273|
   274|export type BlockerMemoryEntry = {
   275|  blockerCode: BlockerCode;
   276|  firstSeenAt: string;
   277|  lastSeenAt: string;
   278|  occurrenceCount: number;
   279|  lastHttpStatus: number | null;
   280|  requiredOwnerAction: string;
   281|};
   282|
   283|const blockerMemory = new Map<BlockerCode, BlockerMemoryEntry>();
   284|
   285|/** The repetition threshold — after this many occurrences the gate refuses to re-run. */
   286|export const BLOCKER_REPEAT_THRESHOLD = 2;
   287|
   288|/**
   289| * Record a blocker sighting in memory. Returns the updated entry.
   290| * Pure-ish (mutates module-level map) but deterministic given the clock.
   291| */
   292|export function recordBlocker(
   293|  blockerCode: BlockerCode,
   294|  httpStatus: number | null,
   295|  requiredOwnerAction: string,
   296|  now: Date = new Date(),
   297|): BlockerMemoryEntry {
   298|  const iso = now.toISOString();
   299|  const existing = blockerMemory.get(blockerCode);
   300|  if (existing) {
   301|    const updated: BlockerMemoryEntry = {
   302|      ...existing,
   303|      lastSeenAt: iso,
   304|      occurrenceCount: existing.occurrenceCount + 1,
   305|      lastHttpStatus: httpStatus,
   306|    };
   307|    blockerMemory.set(blockerCode, updated);
   308|    return updated;
   309|  }
   310|  const entry: BlockerMemoryEntry = {
   311|    blockerCode,
   312|    firstSeenAt: iso,
   313|    lastSeenAt: iso,
   314|    occurrenceCount: 1,
   315|    lastHttpStatus: httpStatus,
   316|    requiredOwnerAction,
   317|  };
   318|  blockerMemory.set(blockerCode, entry);
   319|  return entry;
   320|}
   321|
   322|/** Read a blocker memory entry, or null when never seen. */
   323|export function getBlockerMemory(blockerCode: BlockerCode): BlockerMemoryEntry | null {
   324|  return blockerMemory.get(blockerCode) ?? null;
   325|}
   326|
   327|/** Clear blocker memory — call this after the owner has resolved the blocker. */
   328|export function clearBlockerMemory(blockerCode?: BlockerCode): void {
   329|  if (blockerCode) {
   330|    blockerMemory.delete(blockerCode);
   331|  } else {
   332|    blockerMemory.clear();
   333|  }
   334|}
   335|
   336|/** Snapshot the entire blocker memory (for audit/diagnostics). */
   337|export function snapshotBlockerMemory(): BlockerMemoryEntry[] {
   338|  return [...blockerMemory.values()];
   339|}
   340|
   341|/** True when a blocker has hit the repeat threshold (spin-loop guard fires). */
   342|export function isRepeatedBlocker(blockerCode: BlockerCode): boolean {
   343|  const entry = blockerMemory.get(blockerCode);
   344|  return Boolean(entry && entry.occurrenceCount >= BLOCKER_REPEAT_THRESHOLD);
   345|}
   346|
   347|// ─── Capability check implementation ─────────────────────────────────
   348|
   349|export type FeasibilityGateInput = {
   350|  prompt: string;
   351|  taskId: string;
   352|  /** Whether a verified owner session is present right now. */
   353|  ownerSessionPresent: boolean;
   354|  /** Injectable live probes (defaults to DEFAULT_CREDENTIAL_PROBES). */
   355|  probes?: CredentialProbeMap;
   356|  /** Injectable env snapshot for tests (defaults to process.env). */
   357|  env?: Record<string, string | undefined>;
   358|  /** Skip live network probes (tests). When true, only presence is checked. */
   359|  skipLiveProbes?: boolean;
   360|};
   361|
   362|type ResolvedCredential = {
   363|  present: boolean;
   364|  value: string;
   365|  source: 'ivx' | 'fallback' | 'none';
   366|  sourceVar: string | null;
   367|};
   368|
   369|function resolveCredential(
   370|  ivxName: RequiredCredential,
   371|  fallbackName: string | null,
   372|  env: Record<string, string | undefined>,
   373|): ResolvedCredential {
   374|  const ivxValue = (env[ivxName] ?? '').trim();
   375|  if (ivxValue) return { present: true, value: ivxValue, source: 'ivx', sourceVar: ivxName };
   376|  if (fallbackName) {
   377|    const fallbackValue = (env[fallbackName] ?? '').trim();
   378|    if (fallbackValue) return { present: true, value: fallbackValue, source: 'fallback', sourceVar: fallbackName };
   379|  }
   380|  return { present: false, value: '', source: 'none', sourceVar: null };
   381|}
   382|
   383|const CREDENTIAL_FALLBACKS: Record<RequiredCredential, string | null> = {
   384|  IVX_GITHUB_TOKEN: 'GITHUB_TOKEN',
   385|  IVX_RENDER_API_KEY: 'RENDER_API_KEY',
   386|  IVX_RENDER_SERVICE_ID: 'RENDER_SERVICE_ID',
   387|  IVX_SUPABASE_URL: 'SUPABASE_URL',
   388|  IVX_SUPABASE_SERVICE_ROLE_KEY: 'SUPABASE_SERVICE_ROLE_KEY',
   389|  IVX_OWNER_TOKEN: null,
   390|};
   391|
   392|async function probeCredential(
   393|  cred: RequiredCredential,
   394|  value: string,
   395|  probes: CredentialProbeMap,
   396|  skipLiveProbes: boolean,
   397|): Promise<{ ok: boolean; httpStatus: number | null; detail: string; authStatus: 'authenticated' | 'rejected' | 'untested' }> {
   398|  if (skipLiveProbes || !value) {
   399|    return { ok: !value ? false : true, httpStatus: null, detail: value ? 'presence check only (live probe skipped)' : 'missing', authStatus: 'untested' };
   400|  }
   401|  const probe = probes[cred];
   402|  if (!probe) {
   403|    return { ok: true, httpStatus: null, detail: 'no probe registered (presence only)', authStatus: 'untested' };
   404|  }
   405|  const result = await probe(value);
   406|  return {
   407|    ok: result.ok,
   408|    httpStatus: result.httpStatus,
   409|    detail: result.detail,
   410|    authStatus: result.ok ? 'authenticated' : 'rejected',
   411|  };
   412|}
   413|
   414|async function checkCapability(
   415|  capability: CapabilityId,
   416|  input: FeasibilityGateInput,
   417|  probes: CredentialProbeMap,
   418|  env: Record<string, string | undefined>,
   419|): Promise<CapabilityCheckResult> {
   420|  const base: CapabilityCheckResult = {
   421|    capability,
   422|    ok: false,
   423|    blockerCode: null,
   424|    exactBlocker: null,
   425|    requiredVariable: null,
   426|    runtimeSource: 'not_applicable',
   427|    httpStatus: null,
   428|    credentialPresent: false,
   429|    credentialPrefix: null,
   430|    credentialLength: 0,
   431|    authStatus: 'not_applicable',
   432|    testDetail: null,
   433|  };
   434|
   435|  switch (capability) {
   436|    case 'read_files':
   437|    case 'write_files':
   438|    case 'run_tests':
   439|      // In-process capabilities — always available in the backend runtime.
   440|      return { ...base, ok: true, runtimeSource: 'not_applicable', testDetail: 'in-process capability always available' };
   441|
   442|    case 'commit':
   443|    case 'push_github': {
   444|      const cred: RequiredCredential = 'IVX_GITHUB_TOKEN';
   445|      const resolved = resolveCredential(cred, CREDENTIAL_FALLBACKS[cred], env);
   446|      const probe = await probeCredential(cred, resolved.value, probes, input.skipLiveProbes ?? false);
   447|      const result: CapabilityCheckResult = {
   448|        ...base,
   449|        requiredVariable: cred,
   450|        runtimeSource: resolved.source,
   451|        credentialPresent: resolved.present,
   452|        credentialPrefix: maskCredential(resolved.value),
   453|        credentialLength: resolved.value.length,
   454|        httpStatus: probe.httpStatus,
   455|        authStatus: probe.authStatus,
   456|        testDetail: probe.detail,
   457|      };
   458|      if (!resolved.present) {
   459|        return { ...result, blockerCode: 'GITHUB_TOKEN_MISSING', exactBlocker: `${cred} (or fallback ${CREDENTIAL_FALLBACKS[cred]}) is not present in the runtime env.` };
   460|      }
   461|      if (!probe.ok) {
   462|        const code: BlockerCode = probe.httpStatus === 401 ? 'GITHUB_TOKEN_REVOKED' : 'GITHUB_TOKEN_REVOKED';
   463|        return { ...result, blockerCode: code, exactBlocker: `GitHub API rejected the token: ${probe.detail} (HTTP ${probe.httpStatus ?? 'n/a'}).` };
   464|      }
   465|      // For push, also check GITHUB_REPO shape.
   466|      if (capability === 'push_github') {
   467|        const repo = (env.GITHUB_REPO ?? env.IVX_GITHUB_REPO ?? '').trim();
   468|        if (!repo || !/^[\w.-]+\/[\w.-]+$/.test(repo)) {
   469|          return { ...result, blockerCode: 'GITHUB_REPO_INVALID', exactBlocker: `GITHUB_REPO is missing or malformed (expected "owner/repo", got "${repo || '<empty>'}").` };
   470|        }
   471|      }
   472|      return { ...result, ok: true };
   473|    }
   474|
   475|    case 'trigger_render_deploy': {
   476|      const keyCred: RequiredCredential = 'IVX_RENDER_API_KEY';
   477|      const idCred: RequiredCredential = 'IVX_RENDER_SERVICE_ID';
   478|      const keyResolved = resolveCredential(keyCred, CREDENTIAL_FALLBACKS[keyCred], env);
   479|      const keyProbe = await probeCredential(keyCred, keyResolved.value, probes, input.skipLiveProbes ?? false);
   480|      const keyResult: CapabilityCheckResult = {
   481|        ...base,
   482|        requiredVariable: keyCred,
   483|        runtimeSource: keyResolved.source,
   484|        credentialPresent: keyResolved.present,
   485|        credentialPrefix: maskCredential(keyResolved.value),
   486|        credentialLength: keyResolved.value.length,
   487|        httpStatus: keyProbe.httpStatus,
   488|        authStatus: keyProbe.authStatus,
   489|        testDetail: keyProbe.detail,
   490|      };
   491|      if (!keyResolved.present) {
   492|        return { ...keyResult, blockerCode: 'RENDER_KEY_MISSING', exactBlocker: `${keyCred} (or fallback ${CREDENTIAL_FALLBACKS[keyCred]}) is not present in the runtime env.` };
   493|      }
   494|      if (!keyProbe.ok) {
   495|        return { ...keyResult, blockerCode: 'RENDER_KEY_MISSING', exactBlocker: `Render API rejected the key: ${keyProbe.detail} (HTTP ${keyProbe.httpStatus ?? 'n/a'}).` };
   496|      }
   497|      const idResolved = resolveCredential(idCred, CREDENTIAL_FALLBACKS[idCred], env);
   498|      const idProbe = await probeCredential(idCred, idResolved.value, probes, input.skipLiveProbes ?? false);
   499|      if (!idResolved.present || !idProbe.ok) {
   500|        return {
   501|          ...keyResult,
   502|          ok: false,
   503|          requiredVariable: idCred,
   504|          runtimeSource: idResolved.source,
   505|          credentialPresent: idResolved.present,
   506|          credentialPrefix: maskCredential(idResolved.value),
   507|          credentialLength: idResolved.value.length,
   508|          httpStatus: idProbe.httpStatus,
