   627|export async function runPreExecutionFeasibilityGate(
   628|  input: FeasibilityGateInput,
   629|): Promise<FeasibilityGateResult> {
   630|  const intent = classifyTaskIntent(input.prompt);
   631|  const required = requiredCapabilitiesFor(intent);
   632|  const probes = input.probes ?? DEFAULT_CREDENTIAL_PROBES;
   633|  const env = input.env ?? process.env;
   634|  const generatedAt = new Date().toISOString();
   635|
   636|  // Conversational prompts need no capabilities — always READY.
   637|  if (required.length === 0) {
   638|    return {
   639|      state: 'READY',
   640|      taskId: input.taskId,
   641|      capabilities: [],
   642|      repeatedBlocker: false,
   643|      generatedAt,
   644|      marker: IVX_PRE_EXECUTION_FEASIBILITY_GATE_MARKER,
   645|    };
   646|  }
   647|
   648|  // Spin-loop guard: if ANY required capability already has a repeated blocker
   649|  // in memory, refuse to re-run the checks. Return REPEATED_BLOCKER immediately.
   650|  for (const capability of required) {
   651|    // We can only check blocker memory by code, not by capability, so we look
   652|    // at all entries and see if any are repeated. The full mapping happens
   653|    // after the first run records the blocker. This is intentional: the FIRST
   654|    // run always executes the checks so we get a fresh evidence point; only
   655|    // the SECOND identical blocker triggers the spin guard.
   656|    void capability;
   657|  }
   658|  const repeatedEntries = snapshotBlockerMemory().filter((e) => e.occurrenceCount >= BLOCKER_REPEAT_THRESHOLD);
   659|  if (repeatedEntries.length > 0) {
   660|    // Find a repeated blocker that would plausibly affect this task. We are
   661|    // conservative: ANY repeated blocker blocks re-execution until cleared.
   662|    const entry = repeatedEntries[0];
   663|    return {
   664|      state: 'BLOCKED',
   665|      taskId: input.taskId,
   666|      blockerCode: 'REPEATED_BLOCKER',
   667|      exactBlocker: `Blocker ${entry.blockerCode} has recurred ${entry.occurrenceCount} times. The gate refuses to loop. Owner action required: ${entry.requiredOwnerAction}`,
   668|      failedCapability: 'verify_owner_session',
   669|      requiredVariable: null,
   670|      runtimeSource: 'none',
   671|      httpStatus: entry.lastHttpStatus,
   672|      nextOwnerAction: entry.requiredOwnerAction,
   673|      capabilities: [],
   674|      repeatedBlocker: true,
   675|      generatedAt,
   676|      marker: IVX_PRE_EXECUTION_FEASIBILITY_GATE_MARKER,
   677|    };
   678|  }
   679|
   680|  // Run capability checks in order. First failure wins.
   681|  const capabilities: CapabilityCheckResult[] = [];
   682|  for (const capability of required) {
   683|    const result = await checkCapability(capability, input, probes, env);
   684|    capabilities.push(result);
   685|    if (!result.ok) {
   686|      const blockerCode = result.blockerCode ?? 'TOOL_NOT_AVAILABLE';
   687|      const exactBlocker = result.exactBlocker ?? 'Capability check failed without a specific blocker.';
   688|      const nextOwnerAction = ownerActionFor(blockerCode);
   689|      // Record in blocker memory (spin-loop prevention).
   690|      recordBlocker(blockerCode, result.httpStatus, nextOwnerAction);
   691|      return {
   692|        state: 'BLOCKED',
   693|        taskId: input.taskId,
   694|        blockerCode,
   695|        exactBlocker,
   696|        failedCapability: capability,
   697|        requiredVariable: result.requiredVariable,
   698|        runtimeSource: result.runtimeSource,
   699|        httpStatus: result.httpStatus,
   700|        nextOwnerAction,
   701|        capabilities,
   702|        repeatedBlocker: false,
   703|        generatedAt,
   704|        marker: IVX_PRE_EXECUTION_FEASIBILITY_GATE_MARKER,
   705|      };
   706|    }
   707|  }
