   709|  return {
   710|    state: 'READY',
   711|    taskId: input.taskId,
   712|    capabilities,
   713|    repeatedBlocker: false,
   714|    generatedAt,
   715|    marker: IVX_PRE_EXECUTION_FEASIBILITY_GATE_MARKER,
