   445|function summarizeAuthDiagnosticForDetail(snapshot: IVXOwnerAIAuthDiagnosticSnapshot | null): string {
   446|  if (!snapshot) {
   447|    return '';
   448|  }
   449|  if (snapshot.diagnosticFetchError) {
   450|    return ` [auth-diagnostic fetch failed: ${snapshot.diagnosticFetchError}]`;
   451|  }
   452|  const parts: string[] = [];
   453|  if (snapshot.rootCause) parts.push(snapshot.rootCause);
   454|  const flags: string[] = [];
   455|  if (snapshot.issuerMatchesBackendProject === false) flags.push('issuer-mismatch');
   456|  if (snapshot.tokenExpired === true) flags.push('token-expired');
   457|  if (snapshot.supabaseUserFound === false) flags.push('supabase-getUser-rejected');
   458|  if (snapshot.tokenPresent === false) flags.push('no-bearer-received-by-backend');
   459|  if (flags.length > 0) parts.push(`flags=[${flags.join(',')}]`);
   460|  if (snapshot.tokenIssuer || snapshot.expectedIssuer) {
   461|    parts.push(`tokenIss=${snapshot.tokenIssuer ?? 'none'} expectedIss=${snapshot.expectedIssuer ?? 'none'}`);
   462|  }
   463|  if (snapshot.supabaseErrorMessage) parts.push(`supabaseErr="${snapshot.supabaseErrorMessage}"`);
   464|  if (typeof snapshot.secondsUntilExpiry === 'number') parts.push(`expiresIn=${snapshot.secondsUntilExpiry}s`);
   465|  return parts.length > 0 ? ` [auth-diagnostic: ${parts.join('; ')}]` : '';
   466|}
